// COMVEST-UNICAMP 2025 Questions - Complete Set (60 questions)
export const COMVEST_UNICAMP_2025_ALL: any[] = [
  { id: 'comvest_2025_001', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Doenças Infecto-Parasitárias', text: 'Um paciente transgênero de 28 anos comparece à unidade de emergência apresentando febre alta (39,2°C), cefaleia intensa, prostração, dor retroorbitária e rash cutâneo. Ao exame físico, constata-se pressão arterial de 90/60 mmHg, enchimento capilar lentificado e hepatomegalia dolorosa. Os exames laboratoriais evidenciam hematócrito elevado e plaquetopenia (52.000/mm³). No prontuário eletrônico, há discrepância entre o nome de registro civil e a identidade de gênero apresentada pelo paciente. Considerando o manejo clínico adequado e os princípios da Política Nacional de Saúde Integral LGBT, assinale a alternativa correta:', options: ['O médico deve focar exclusivamente no quadro clínico de dengue grave, evitando abordagens sobre identidade de gênero durante o atendimento de emergência, pois temas sensíveis podem ser discutidos apenas após a estabilização completa do paciente.', 'A prioridade deve ser corrigir a hipotensão com uso de drogas vasoativas, devido ao maior risco cardiovascular associado à terapia hormonal em pessoas transgênero, além de prescrever anti-inflamatórios não esteroidais para o controle da febre e da dor.', 'A conduta adequada inclui hidratação oral intensiva, uso de dipirona para controle térmico, orientação para retorno em 24 horas, e encaminhamento para serviço especializado no processo transexualizador após a resolução do quadro agudo.', 'O médico deve iniciar antibioticoterapia de amplo espectro imediatamente, pois pacientes em terapia hormonal têm maior susceptibilidade a infecções bacterianas graves, além de registrar o atendimento com o nome civil para evitar erros na identificação laboratorial.', 'O médico deve priorizar a estabilização hemodinâmica com reposição volêmica endovenosa utilizando cristaloides, prescrever antitérmico (paracetamol), registrar o atendimento utilizando o nome social do paciente, investigar uso de hormonioterapia que possa interagir com o tratamento, e solicitar vaga em UTI devido à gravidade do quadro.'], correctIndex: 4 },
  { id: 'comvest_2025_002', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Cardiologia e Alterações Vasculares', text: 'Um paciente masculino, 58 anos, tabagista e hipertenso, é admitido no pronto-socorro com dor torácica opressiva há aproximadamente 40 minutos, irradiando para o braço esquerdo. O paciente refere que a dor não melhora com repouso e vem associada a sudorese intensa. O eletrocardiograma (ECG) realizado na admissão revela supradesnivelamento do segmento ST em derivações anteriores. A equipe médica realiza coleta de troponina, confirma a elevação enzimática e inicia a abordagem terapêutica. Com base nesse caso, assinale a alternativa correta sobre a Síndrome Coronariana Aguda (SCA):', options: ['O tratamento precoce com fibrinolíticos é indicado apenas em casos de SCA com elevamento de troponina, independentemente do achado no eletrocardiograma, e deve ser evitado em pacientes com angina instável.', 'A abordagem inicial de um paciente com SCA envolve a administração de anticoagulantes, inibidores da glicoproteína IIb/IIIa e fibrinolíticos, independentemente da apresentação clínica.', 'No diagnóstico da SCA, o eletrocardiograma (ECG) é essencial, pois a presença de elevação do segmento ST ou inversão da onda T podem orientar o diagnóstico e a estratégia terapêutica, como a necessidade de intervenção coronária percutânea (ICP).', 'A principal estratégia de prevenção secundária após o tratamento de um infarto do miocárdio com supra de ST (IMST) é a interrupção do uso de aspirina, visto que a anticoagulação prolongada está associada a risco elevado de sangramentos.', 'A diferenciação entre infarto do miocárdio com e sem supra de ST (IMST e IMSEM) é feita exclusivamente pela dosagem de marcadores cardíacos, como troponina, sem necessidade de exame eletrocardiográfico.'], correctIndex: 2 },
  { id: 'comvest_2025_003', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Doenças Reumatológicas e do Sistema Imunológico', text: 'Mulher de 38 anos apresenta dor difusa há mais de 3 anos, com intensidade variável (5-8/10), predominantemente em região cervical, ombros, lombar e quadris, associada a fadiga persistente, distúrbios do sono e episódios de cefaleia. Ao exame físico, apresenta múltiplos tender points positivos, sem sinais inflamatórios articulares. Exames laboratoriais (hemograma, VHS, PCR, função tireoidiana, fator reumatoide e FAN) dentro da normalidade. Sobre este quadro clínico, analise as afirmativas a seguir: I.O diagnóstico provável é fibromialgia, uma condição de dor crônica centralizada caracterizada por sensibilização central. II.A presença de pelo menos 11 dos 18 tender points clássicos é obrigatória para o diagnóstico, segundo os critérios atuais do Colégio Americano de Reumatologia. III.A abordagem terapêutica ideal envolve tratamento multimodal com terapia cognitivo-comportamental, exercício físico e farmacoterapia. IV.Entre os medicamentos podem ser utilizados os antidepressivos duais (como duloxetine e milnaciprano) e anticonvulsivantes (como pregabalina). É correto o que se afirma em:', options: ['II e III, apenas.', 'I e IV, apenas.', 'I, II, III e IV.', 'II, apenas.', 'I, III e IV, apenas.'], correctIndex: 4 },
  { id: 'comvest_2025_004', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Endocrinologia', text: 'Uma Unidade Básica de Saúde (UBS) identificou que 35% dos pacientes diabéticos acompanhados apresentavam hemoglobina glicada acima de 8,5%, com alta prevalência de retinopatia diabética inicial. Diante dessa situação, o coordenador da unidade decidiu implementar um programa educacional para qualificação da equipe multiprofissional no manejo do diabetes mellitus tipo 2. Considerando o referencial teórico da modelização avaliativa de intervenções em saúde e a fisiopatologia das complicações crônicas do diabetes, qual das seguintes propostas integra corretamente os princípios da avaliação de programas com os mecanismos patogênicos envolvidos na microangiopatia diabética?', options: ['A avaliação do programa deve focar exclusivamente nos resultados finais da intervenção educacional, priorizando a análise da redução dos níveis pressóricos dos pacientes diabéticos, considerando que a principal causa da retinopatia diabética é a hipertensão arterial sistêmica associada à progressiva insuficiência renal, dispensando a participação dos profissionais executores na construção dos indicadores avaliativos.', 'A modelização consensuada do programa educacional deve incluir indicadores de monitoramento da redução da via do poliol e da glicação não enzimática de proteínas nos pacientes, como medidas de efetividade da intervenção, contemplando o mapeamento de recursos disponíveis, atividades educativas implementadas e efeitos sobre o controle glicêmico, permitindo a construção participativa do processo avaliativo entre os diferentes atores envolvidos.', 'Os componentes estruturais da modelização avaliativa devem enfatizar a prevenção de complicações macrovasculares como desfecho primário, uma vez que o espessamento da membrana basal dos vasos retinianos ocorre predominantemente por mecanismos imunológicos, com a avaliação realizada por consultores externos que não participam da execução do programa para garantir objetividade e imparcialidade.', 'A modelização deve priorizar a avaliação da adesão dos profissionais ao programa educacional, utilizando questionários padronizados nacionais sem adaptações locais, considerando que a disfunção plaquetária é o principal mecanismo fisiopatológico envolvido na retinopatia diabética e que a construção de consensos entre os participantes pode comprometer a objetividade científica do processo avaliativo.', 'O desenho avaliativo deve centrar-se na análise do uso de medicamentos anti-VEGF pelos pacientes, desconsiderando adaptações regionais do programa educacional, já que o fator primário da microangiopatia diabética é a produção excessiva do fator de crescimento endotelial vascular independente do controle glicêmico, com avaliações trimestrais realizadas exclusivamente por especialistas em oftalmologia.'], correctIndex: 1 },
  { id: 'comvest_2025_005', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Nefrologia', text: 'Um homem negro de 68 anos, hipertenso e diabético há 15 anos, comparece à Unidade Básica de Saúde com queixas de cansaço progressivo e edema de membros inferiores. Durante a consulta, o médico constata pressão arterial de 162/98 mmhg e glicemia capilar de 210 mg/dL. Exames recentes evidenciam creatinina de 1,9 mg/dL (valor anterior de 1,2 mg/dL há 6 meses). Ciente da Política Nacional de Saúde Integral da População Negra (PNSIPN) e o manejo adequado deste caso, assinale a alternativa correta:', options: ['O aumento da creatinina sérica não possui relevância clínica significativa neste caso, já que pacientes negros possuem naturalmente valores mais elevados deste parâmetro, independentemente da função renal.', 'O tratamento deve ser focado exclusivamente no controle medicamentoso da hipertensão e diabetes, sem necessidade de considerar determinantes sociais da saúde, como acesso a alimentação adequada e condições de moradia.', 'A abordagem deve reconhecer que a hipertensão e o diabetes são mais prevalentes e potencialmente mais graves na população negra devido a fatores biológicos, sociais e ambientais, sendo necessário avaliar a função renal com maior atenção, considerando que a creatinina sérica e o débito urinário são parâmetros importantes para o diagnóstico de lesão renal.', 'O paciente deve ser encaminhado imediatamente ao nefrologista, pois a elevação da creatinina em pacientes negros sempre indica doença renal terminal, devido à maior suscetibilidade genética desta população a complicações renais da hipertensão.', 'A avaliação da função renal em pacientes negros deve utilizar apenas a proteinúria como parâmetro, pois a creatinina sérica não é um indicador confiável de lesão renal nesta população.'], correctIndex: 2 },
  { id: 'comvest_2025_006', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Políticas Públicas, Planejamento e Gestão em Saúde Pública', text: 'Uma Secretaria Municipal de Saúde estabeleceu parceria com uma Instituição de Ensino Superior (IES) para implementar um projeto de integração ensino-serviço em uma unidade hospitalar de referência em média complexidade. Neste hospital, estudantes do internato médico realizam estágio supervisionado em um ambulatório de especialidades que atende casos de lombalgias crônicas referenciados pela Atenção Primária à Saúde. Considerando os fundamentos teórico-conceituais da integração ensino-serviço e suas implicações para a formação médica e a qualificação da assistência, analise as afirmativas a seguir: I.A efetiva integração ensino-serviço neste cenário requer pactuação prévia entre gestores, docentes, profissionais e representantes dos usuários, estabelecendo relações horizontais que contemplem necessidades formativas, assistenciais e comunitárias, superando a mera utilização do espaço hospitalar como campo de prática. II.A inserção dos internos no ambulatório hospitalar constitui oportunidade de compreensão dos fluxos assistenciais da rede de atenção e do sistema de referência e contrarreferência, especialmente se articulada a vivências na Atenção Primária, possibilitando a formação de um médico com visão integral do cuidado. III.O hospital secundário, por concentrar tecnologias de média complexidade e especialistas, deve priorizar a formação técnico-científica dos estudantes em detrimento da abordagem psicossocial das lombalgias, deixando os aspectos relacionais do cuidado para serem desenvolvidos em cenários da Atenção Primária. IV.A presença de discentes no ambiente hospitalar potencializa a educação permanente dos profissionais do serviço mediante trocas de conhecimentos e reflexão crítica sobre as práticas cotidianas, desde que estruturada como processo dialógico e não como transferência unidirecional de saberes acadêmicos. V.A integração ensino-serviço no contexto hospitalar deve ser operacionalizada prioritariamente por meio de convênios formais entre as instituições, prescindindo de transformações nos processos de trabalho e nas concepções pedagógicas que fundamentam a formação médica. É correto o que se afirma em:', options: ['III e V, apenas.', 'II e IV, apenas.', 'I, II, III, IV e V.', 'I, III e V, apenas.', 'I, II e IV, apenas.'], correctIndex: 4 },
  { id: 'comvest_2025_007', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Gastroenterologia', text: 'Um paciente masculino, 45 anos, comparece à Unidade Básica de Saúde (UBS) relatando sensação de plenitude gástrica, queimação epigástrica e desconforto abdominal recorrente nos últimos seis meses, especialmente após as refeições. Nega vômitos, disfagia ou episódios de hematoquezia. Relata que faz uso frequente de anti-inflamatórios devido a dores articulares. Diante desse quadro clínico, qual das alternativas descreve corretamente a síndrome dispéptica?', options: ['A síndrome dispéptica caracteriza-se por regurgitação ácida, disfagia progressiva e odinofagia.', 'A síndrome dispéptica caracteriza-se por diarreia crônica como sintoma principal e sempre requer hospitalização.', 'A síndrome dispéptica caracteriza-se por dor abdominal predominantemente nos quadrantes inferiores e alteração do hábito intestinal.', 'A síndrome dispéptica caracteriza-se por sensação de plenitude pós-prandial, saciedade precoce e dor epigástrica.', 'A síndrome dispéptica caracteriza-se por dor torácica retroesternal relacionada ao esforço físico e irradiação para membro superior.'], correctIndex: 3 },
  { id: 'comvest_2025_008', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Clínica Médica Humana, Medicina Intensiva', text: 'Um paciente de 65 anos, hipertenso e diabético, é admitido na emergência com febre alta, taquicardia e confusão mental há 12 horas. No exame físico, apresenta hipotensão (PA: 85x50 mmHg), taquipneia (FR: 24 irpm) e tempo de enchimento capilar aumentado. Exames laboratoriais mostram leucocitose com desvio à esquerda, lactato elevado e disfunção renal. O médico suspeita de um quadro infeccioso grave e inicia antibioticoterapia de amplo espectro e reposição volêmica. Com base nesse cenário, e considerando a relação entre Sepse e a Síndrome da Resposta Inflamatória Sistêmica (SIRS), assinale a alternativa correta:', options: ['A resposta inflamatória sistêmica (SIRS) é um conceito clínico que pode ocorrer independentemente de infecção e é caracterizada por pelo menos dois critérios, sendo um deles a hipotensão persistente.', 'A sepse pode ser diagnosticada quando um paciente apresenta sinais de SIRS com sinais de infecção clínica confirmada e não necessita de testes laboratoriais adicionais para confirmação.', 'A sepse é caracterizada exclusivamente por infecção bacteriana, com a presença de leucocitose e febre como principais critérios diagnósticos.', 'Em sepse grave, a falência de múltiplos órgãos é uma condição frequentemente reversível, sendo tratada apenas com administração de antibióticos e fluidos intravenosos.', 'A SIRS pode ser causada por infecções, trauma, pancreatite e outras condições, mas a sepse só deve ser diagnosticada quando houver uma resposta inflamatória associada a infecção causando disfunção orgânica.'], correctIndex: 4 },
  { id: 'comvest_2025_009', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Cardiologia e Alterações Vasculares, Nefrologia', text: 'Um paciente de 65 anos, com histórico de hipertensão arterial mal controlada e diabetes mellitus tipo 2, chega à emergência hospitalar apresentando PA de 210/130 mmHg, confusão mental, cefaleia intensa, edema de papila bilateral ao exame de fundo de olho e creatinina sérica de 2,8 mg/dL. Durante a discussão clínica para definição da conduta, um estudante do último ano de medicina propõe abordagem terapêutica baseada em evidências científicas. Considerando este cenário clínico de emergência hipertensiva com lesão renal aguda e os princípios da avaliação programática na formação médica, qual das alternativas a seguir representa simultaneamente a conduta terapêutica mais adequada para o paciente e o melhor método avaliativo do desempenho do estudante neste contexto?', options: ['Iniciar a redução gradual da pressão arterial com medicação intravenosa, não ultrapassando 25% da PA inicial nas primeiras 24 horas, e realizar avaliação formativa do estudante com feedback estruturado imediatamente após a discussão do caso.', 'Administrar nitroprussiato de sódio intravenoso para redução imediata da pressão arterial para valores normais, e aplicar avaliação somativa por meio de exame oral sobre emergências hipertensivas após o atendimento.', 'Prescrever inibidor da enzima conversora de angiotensina por via oral em dose otimizada, e implementar avaliação programática com foco exclusivo na capacidade do estudante de interpretar exames laboratoriais e de imagem.', 'Prescrever furosemida intravenosa em alta dose para controle da pressão arterial e da função renal, e utilizar avaliação informativa com coleta de dados sobre o desempenho do estudante para análise posterior pelo colegiado docente.', 'Instituir tratamento com betabloqueador oral associado a diurético tiazídico, e realizar avaliação somativa no final do estágio com registro formal do desempenho do estudante neste caso específico.'], correctIndex: 0 },
  { id: 'comvest_2025_010', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Clínica Médica Humana, Neurologia', text: 'Uma paciente de 28 anos comparece ao ambulatório relatando crises de enxaqueca cada vez mais frequentes e intensas nos últimos três meses. Ela descreve dores pulsáteis unilaterais, associadas a náuseas, fotofobia e fonofobia, que a obrigam a interromper suas atividades diárias. Durante a anamnese, refere alta carga de trabalho, relatando que dorme apenas 4 horas por noite durante a semana, além de fazer uso frequente de analgésicos para alívio da dor. Questionada sobre sua alimentação, relata que toma café apenas ocasionalmente e mantém boa ingestão hídrica. Diante desse quadro, qual das opções abaixo representa um fator de risco reconhecido para crises mais frequentes e intensas de enxaqueca?', options: ['Uso regular de analgésicos anti-inflamatórios não esteroides (AINEs).', 'Alta ingestão de potássio.', 'Consumo elevado de líquidos.', 'Uso de cafeína mesmo que em pequenas quantidades.', 'Privação de sono ou distúrbios do sono.'], correctIndex: 4 },
  { id: 'comvest_2025_011', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Pediatria e Neonatologia, Nefrologia', text: 'Uma paciente de 10 anos, previamente hígida, é levada ao pronto-atendimento devido a inchaço progressivo, iniciado nas pálpebras e evoluindo para edema generalizado nos últimos dias. A mãe relata que a criança também tem apresentado redução no volume urinário e que sua urina está espumosa. No exame físico, a paciente apresenta anasarca, pressão arterial normal e não há sinais de febre ou infecção associada. Os exames laboratoriais revelam proteinúria maciça (> 3,5 g/24h), hipoalbuminemia e hipercolesterolemia. Diante desse quadro clínico, qual das alternativas descreve corretamente os sinais e sintomas característicos da síndrome nefrótica?', options: ['Dor torácica, anasarca e proteinúria.', 'Anasarca e proteinúria.', 'Proteinúria e hipotensão arterial.', 'Edema assimétrico de membros inferiores e proteinúria.', 'Hipotensão e anasarca.'], correctIndex: 1 },
  { id: 'comvest_2025_012', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Pneumologia', text: 'Uma mulher de 28 anos procura atendimento na Unidade Básica de Saúde (UBS) com queixa de tosse seca persistente, dispneia intermitente e chiado no peito, sintomas que pioram à noite e após esforços físicos. Relata episódios frequentes desde a infância, mas sem diagnóstico confirmado. Ao exame físico, apresenta sibilos difusos à ausculta pulmonar. O médico solicita uma espirometria para melhor avaliação. Com base nesse quadro clínico, qual das seguintes afirmações sobre a asma está correta?', options: ['Tosse seca e estertores crepitantes à ausculta são comuns.', 'O tratamento a longo prazo é feito com broncodilatadores de curta ação e antibióticos inalatórios.', 'A espirometria característica dos pacientes com asma demonstra obstrução das vias aéreas (VEF1 inferior a 80% do previsto) e relação VEF1/CVF maior que 75% com resposta ao uso de broncodilador.', 'Broncodilatadores de longa ação estão sempre indicados e o paciente deve ser orientado a sempre levar consigo a medicação.', 'Os principais sintomas incluem tosse seca, dispneia e sibilância.'], correctIndex: 4 },
  { id: 'comvest_2025_013', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Médico da Família', text: 'Um paciente de 72 anos comparece à UBS apresentando dispneia progressiva, limitação para atividades diárias e agravamento do padrão de tosse produtiva, com mudança da coloração do escarro. Durante a consulta, o médico observa múltiplas contusões em diferentes estágios de cicatrização nos membros superiores e abrasões no dorso. Após estabelecer vínculo de confiança, o idoso revela que seu filho, com quem reside, tem consumido álcool excessivamente e se tornado agressivo, especialmente quando o pai tosse durante a noite. Refere histórico de tabagismo (60 maços/ano), duas internações por exacerbação de DPOC no último ano, e que o filho frequentemente se apropria de sua aposentadoria e não permite que o pai adquira suas medicações regularmente. Considerando a complexidade deste caso que envolve manejo clínico da DPOC e situação de vulnerabilidade por violência, assinale a alternativa que representa a conduta mais adequada:', options: ['Focar no tratamento da DPOC com broncodilatadores de longa ação e corticoides inalatórios, orientando o idoso sobre a importância da cessação tabágica, e sugerir que tente dialogar com o filho sobre a situação de violência antes de qualquer intervenção externa.', 'Prescrever corticoide oral e antibiótico para a exacerbação da DPOC, orientar o paciente a procurar ajuda de outros familiares e retornar em 30 dias para reavaliação clínica, evitando interferir na dinâmica familiar para não piorar a situação de violência.', 'Encaminhar o paciente ao pneumologista para avaliação especializada da DPOC, sugerindo que ele considere mudar-se para uma instituição de longa permanência para idosos como solução definitiva para o problema de violência.', 'Internar o paciente imediatamente para tratar a exacerbação da DPOC e afastá-lo temporariamente da situação de violência, sem realizar notificação para preservar o vínculo terapêutico com a família.', 'Avaliar clinicamente e tratar a exacerbação da DPOC com antibioticoterapia oral, otimizar a terapia broncodilatadora e reforçar a indicação de cessar o tabagismo. O caso de violência deve ser notificado aos órgãos competentes, deve-se acionar a rede de proteção social, elaborar relatório médico detalhado das lesões, e articular com CAPS AD para abordagem do filho dependente químico.'], correctIndex: 4 },
  { id: 'comvest_2025_014', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Clínica Médica Humana, Pneumologia', text: 'Um homem de 32 anos, diagnosticado previamente com asma moderada, é levado à emergência por familiares devido a uma crise de dispneia intensa iniciada há cerca de 40 minutos. O paciente apresenta fala entrecortada, uso de musculatura acessória e sibilância difusa à ausculta pulmonar. Seus sinais vitais mostram frequência respiratória de 32 irpm, saturação de O2 de 88% em ar ambiente e frequência cardíaca de 120 bpm. Diante desse quadro, a equipe médica inicia o manejo da crise asmática aguda grave. Com base na conduta inicial apropriada para esse paciente, assinale a alternativa correta:', options: ['Administração de corticosteroides sistêmicos e broncodilatadores inalatórios.', 'Prescrição de antibioticoterapia de amplo espectro.', 'Administração de diuréticos intravenosos.', 'Realização de tomografia de tórax e broncoscopia diagnóstica devem ser realizados após a estabilização do paciente para investigação.', 'Implementação de restrição hídrica e Ventilação não invasiva para prevenir o edema pulmonar.'], correctIndex: 0 },
  { id: 'comvest_2025_015', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Angiologia', text: 'Paciente masculino, 62 anos, tabagista, hipertenso e diabético há 15 anos, apresenta claudicação intermitente em membro inferior direito após caminhar 200 metros. Ao exame físico, observa-se ausência de pulsos poplíteo e distais no membro inferior direito, com índice tornozelo-braquial (ITB) de 0,55 neste membro. Eco-Doppler arterial confirma obstrução de 85% da artéria femoral superficial direita. Considere as afirmativas a seguir sobre a condução deste caso: I.O tratamento inicial deve incluir terapia medicamentosa com antiagregante plaquetário e estatina de alta potência. II.A claudicação intermitente indica doença arterial periférica em estágio IIb de Fontaine, correspondente a limitação moderada da capacidade de marcha. III.O exercício físico supervisionado é considerado tratamento de primeira linha para claudicação, com benefícios comparáveis à revascularização. IV.O ITB de 0,55 indica doença arterial periférica moderada e baixo risco de eventos cardiovasculares futuros. É correto o que se afirma em:', options: ['I e III, apenas.', 'I, II, III e IV.', 'I, II e III, apenas.', 'IV, apenas.', 'II e IV, apenas.'], correctIndex: 2 },
  { id: 'comvest_2025_016', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Médico da Família', text: 'Em uma faculdade de medicina, o coordenador do internato identificou duas necessidades críticas entre os estudantes do último ano: falhas no manejo da hipertensão arterial sistêmica (HAS) e dificuldades na comunicação com pacientes. Foi proposta a implementação de um OSCE integrando essas competências. Considerando os fundamentos da avaliação por OSCE e o manejo da HAS na atenção primária, assinale a alternativa correta:', options: ['O OSCE deve conter múltiplas estações sequenciais sem intervalo, focando na comunicação de complicações graves da hipertensão não-controlada, simulando emergências hipertensivas para avaliar simultaneamente habilidades técnicas e comunicacionais em cenários de alto estresse.', 'A avaliação deve priorizar estações com duração de 30 minutos, permitindo abordagem detalhada da fisiopatologia da hipertensão secundária, que representa 95% dos casos, enfatizando causas endócrinas no checklist, sem necessidade de incorporar feedback imediato ao estudante.', 'As estações devem focar exclusivamente na avaliação de conhecimentos teóricos sobre dietoterapia e medidas comportamentais, utilizando checklist que verifique principalmente o uso de terminologia técnica precisa, sem necessidade de pacientes simulados para demonstrar resistência às mudanças.', 'O checklist deve priorizar a adesão ao protocolo terapêutico baseado em diuréticos tiazídicos como primeira escolha para todos os hipertensos, avaliando a comunicação pela capacidade do estudante de convencer o paciente a aceitar esta conduta padronizada, independentemente de suas preferências.', 'A estação deve simular um cenário ambulatorial com paciente hipertenso primário, utilizando checklist que contemple elementos do protocolo SPIKES, verificação da percepção do paciente sobre sua condição e construção de plano terapêutico compartilhado, reconhecendo que a fisiopatologia envolve disfunção endotelial e hiperatividade simpática.'], correctIndex: 4 },
  { id: 'comvest_2025_017', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia, Doenças Infecto-Parasitárias', text: 'Uma mulher de 28 anos, em situação de rua há 3 anos, gestante de aproximadamente 20 semanas, sem realização de pré-natal, é trazida ao pronto-socorro de um hospital de referência durante período de surto de arboviroses na região. A paciente apresenta febre alta (39,5°C) há 3 dias, cefaleia intensa, dor retroorbitária, mialgia generalizada e exantema maculopapular em face e tronco. Ao exame físico: PA 90/60 mmHg, FC 110 bpm, mucosas hipocoradas (+/4+), desidratação moderada, prova do laço positiva e hepatomegalia dolorosa à palpação. Exames laboratoriais revelam hematócrito de 42% (elevado para o padrão da paciente) e plaquetopenia (85.000/mm³). Considerando o contexto de vulnerabilidade da paciente e os sinais de dengue com sinais de alarme, qual é a conduta mais adequada?', options: ['Administrar corticoterapia endovenosa para controle de possível processo inflamatório sistêmico, prescrever hidratação oral intensiva e encaminhar para unidade de atenção primária após estabilização inicial para seguimento ambulatorial.', 'Realizar hidratação endovenosa em bolus, solicitar vaga em UTI preventivamente, orientar repouso absoluto e isolamento devido ao risco de transmissão da arbovirose para outros pacientes, e iniciar dipirona para controle da febre.', 'Prescrever hidratação oral intensiva com soro de reidratação oral, paracetamol para controle da febre, solicitar ultrassonografia obstétrica e orientar retorno ambulatorial em 48 horas para reavaliação clínica e de exames laboratoriais.', 'Iniciar hidratação endovenosa imediata, monitorar sinais vitais e parâmetros obstétricos continuamente, solicitar internação em leito de alto risco, investigar diagnóstico diferencial com outras arboviroses, notificar o caso e articular com serviço social para garantir seguimento pós-alta e inclusão no pré-natal de alto risco.', 'Iniciar antibioticoterapia de amplo espectro considerando a possibilidade de sepse em paciente imunossuprimida pela gravidez e vulnerabilidade social, além de solicitar exames confirmatórios para dengue antes de iniciar a hidratação parenteral.'], correctIndex: 3 },
  { id: 'comvest_2025_018', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Médico da Família', text: 'Um programa de residência médica em Medicina de Família e Comunidade implementou um sistema de avaliação formativa utilizando Mini-CEX para aprimorar o manejo de pacientes hipertensos e diabéticos. Durante uma dessas avaliações, o residente atende uma paciente de 58 anos com hipertensão arterial sistêmica (PA 158/96 mmHg) e diabetes mellitus tipo 2 (HbA1c 8,5%), que demonstra baixa adesão terapêutica por não compreender os riscos de suas condições. O preceptor observa que o residente apresenta dificuldades na comunicação efetiva com a paciente. Para aprimorar simultaneamente as competências clínicas e comunicacionais do residente neste cenário de atenção primária, qual abordagem seria mais adequada?', options: ['O preceptor deve recomendar que o residente utilize terminologia técnica precisa para aumentar sua credibilidade perante a paciente, evitando adaptações da linguagem que possam parecer simplistas, e priorizar protocolos terapêuticos padronizados independentemente das preferências individuais da paciente.', 'A avaliação pelo Mini-CEX deve focar nas habilidades comunicacionais utilizando escala de pontuação, seguida por feedback estruturado imediato sobre como explicar a fisiopatologia da hipertensão primária e diabetes tipo 2 em linguagem acessível, facilitando a compreensão da paciente sobre riscos cardiovasculares e promovendo decisão compartilhada sobre o tratamento.', 'A avaliação formativa deve enfatizar exclusivamente o conhecimento técnico sobre terapêutica, sugerindo que o caso seja referenciado a especialistas, pois pacientes com diabetes e hipertensão descompensadas simultaneamente não devem ser manejados na atenção primária conforme preconizado pelos protocolos atuais de regulação.', 'Durante o feedback, o preceptor deve orientar o residente a aplicar avaliação OSCE em consultório, com duração mínima de 30 minutos, permitindo demonstrar detalhadamente os riscos da não-adesão, priorizando informações sobre complicações graves para aumentar a adesão através do estímulo ao medo.', 'O feedback ao residente deve ser postergado para momento privado após o atendimento, focando na necessidade de prescrição imediata de medicações combinadas para hipertensão e diabetes, evitando-se discussões sobre mudanças no estilo de vida, já que essas têm baixa efetividade em pacientes com múltiplas comorbidades descompensadas.'], correctIndex: 1 },
  { id: 'comvest_2025_019', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Políticas Públicas, Planejamento e Gestão em Saúde Pública', text: 'Em uma Unidade Básica de Saúde (UBS), o coordenador médico identificou que 40% dos pacientes com hipertensão arterial estavam com níveis pressóricos não controlados, apesar de aderirem à terapia medicamentosa prescrita. Realizando uma análise dos prontuários, verificou-se que as prescrições não seguiam as diretrizes atualizadas de tratamento. Em reunião com a equipe, foi decidida a implementação de um programa de Educação Permanente em Saúde (EPS) sobre manejo da hipertensão arterial sistêmica. No contexto da assistência primária e das estratégias de ensino para profissionais da saúde, qual das seguintes abordagens representa a implementação mais adequada da EPS para modificar essa realidade clínica?', options: ['Desenvolver uma tecnologia educativa digital interativa baseada nos problemas reais dos casos clínicos da unidade, incorporando diretrizes atualizadas sobre hipertensão arterial e promovendo discussões reflexivas entre os profissionais a partir das necessidades identificadas na prática cotidiana.', 'Realizar análise estatística detalhada do perfil dos pacientes hipertensos não controlados, elaborar protocolos específicos baseados nos achados epidemiológicos e implementar um sistema de alertas no prontuário eletrônico para identificar prescrições fora das diretrizes, com avaliação trimestral do desempenho individual dos profissionais.', 'Selecionar um médico e um enfermeiro da equipe para participarem de curso de atualização em hipertensão arterial em hospital terciário, com duração de uma semana, designando-os como multiplicadores responsáveis por repassar o conteúdo aprendido aos demais profissionais através de aulas teóricas.', 'Distribuir materiais impressos com as diretrizes de tratamento da hipertensão arterial para cada profissional, estabelecendo metas de redução da pressão arterial em 30 dias, e aplicar questionários avaliativos mensais para verificar o conhecimento técnico adquirido pela equipe.', 'Convidar especialistas em cardiologia para ministrar palestras expositivas sobre hipertensão arterial na unidade, com apresentação de slides padronizados contendo todas as informações técnicas sobre o tratamento medicamentoso atual, seguida de avaliação somativa dos profissionais.'], correctIndex: 0 },
  { id: 'comvest_2025_020', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Políticas Públicas, Planejamento e Gestão em Saúde Pública', text: 'Uma Unidade Básica de Saúde (UBS) enfrenta dificuldades na continuidade do cuidado de pacientes oncológicos que retornam após tratamento em hospital terciário, especialmente no acompanhamento longitudinal e na articulação com outros serviços da rede. A coordenação da UBS decide implementar processos inovadores de gestão clínica para melhorar a integração com os demais níveis de atenção. Considerando o conceito de inovação em saúde como processo interativo fortemente influenciado pelo contexto organizacional e os princípios fundamentais do sistema público de saúde, analise as afirmativas a seguir: I.A inovação em processos assistenciais na atenção primária deve ser impulsionada pelos determinantes sociais, epidemiológicos e territoriais, mantendo a centralidade nas necessidades dos usuários, e não apenas na incorporação tecnológica, configurando-se como processo dialógico e não-linear entre múltiplos atores da rede de atenção. II.A implementação de sistemas informatizados que conectem a UBS aos serviços especializados e hospitalares constitui inovação tecnológica suficiente para garantir a integralidade do cuidado ao paciente oncológico, dispensando transformações nas relações de trabalho e na cultura organizacional da unidade. III.A organização do cuidado compartilhado ao paciente oncológico requer a construção conjunta entre diferentes profissionais da UBS, serviços especializados e hospitais de referência, superando a fragmentação da atenção e fortalecendo o papel da atenção primária na coordenação do cuidado no território. IV.Em cenários complexos como o acompanhamento de pacientes oncológicos na atenção primária, a inovação em saúde deve ser prioritariamente conduzida pelos centros hospitalares especializados e pela indústria farmacêutica, que detêm o conhecimento técnico-científico necessário para determinar as melhores práticas assistenciais a serem adotadas pela UBS. É correto o que se afirma em:', options: ['II e IV, apenas.', 'I e III, apenas.', 'I, II e III, apenas.', 'IV, apenas.', 'I, II, III e IV.'], correctIndex: 1 },
  { id: 'comvest_2025_021', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Clínica Médica Humana', text: 'Mulher de 27 anos, previamente hígida, comparece ao pronto-socorro com queixa de disúria, polaciúria e urgência miccional há 2 dias. Nega febre, dor lombar ou corrimento vaginal. Relata dois episódios semelhantes nos últimos 6 meses. Exame físico sem alterações significativas. Urina tipo I mostra leucocitúria (35-40 leucócitos/campo) e presença de nitrito positivo. Considere as afirmativas a seguir sobre o manejo deste caso: I.O diagnóstico mais provável é cistite não complicada, sendo dispensável a realização de urocultura antes do início do tratamento. II.A Escherichia coli é o patógeno envolvido em aproximadamente 70-80% dos casos de infecção urinária não complicada em mulheres jovens. III.O tratamento empírico de primeira linha pode ser realizado com nitrofurantoína por 5 dias, fosfomicina em dose única ou sulfametoxazol-trimetoprima por 3 dias, considerando o padrão local de resistência bacteriana. IV.A recorrência de infecção urinária (≥ 3 episódios/ano) justifica investigação urológica com exames de imagem, mesmo em pacientes sem fatores de risco para complicações. É correto o que se afirma em:', options: ['IV, apenas.', 'II e III, apenas.', 'I, II e III, apenas.', 'I e IV, apenas.', 'I, II, III e IV.'], correctIndex: 2 },
  { id: 'comvest_2025_022', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Oncologia, Medicina Preventiva', text: 'Homem de 58 anos, assintomático, comparece à consulta de rotina solicitando "check-up completo para câncer". Tem histórico familiar de câncer colorretal (pai diagnosticado aos 70 anos) e tabagismo ativo de 30 maços/ano. IMC = 27 kg/m2. Sem comorbidades conhecidas. Realizou colonoscopia há 2 anos, normal, e PSA total = 2,8 ng/mL há 6 meses. Nunca realizou outros exames de rastreamento oncológico. Considerando as diretrizes de rastreamento de neoplasias baseadas em evidências científicas, analise as afirmativas a seguir: I.O rastreamento para câncer de pulmão com tomografia computadorizada de baixa dose (TCBD) anual está indicado para este paciente, considerando a carga tabágica de 30 maços/ano e idade entre 50-80 anos. II.O rastreamento para câncer colorretal deve ser mantido com intervalos de 10 anos entre as colonoscopias, uma vez que o exame anterior foi normal e o histórico familiar não configura critério para síndrome hereditária. III.O rastreamento para câncer de próstata com PSA sérico é recomendado de forma indiscriminada para homens acima de 50 anos, dada a alta prevalência desta neoplasia na população masculina. IV.O rastreamento para hepatocarcinoma com ultrassonografia e alfafetoproteína semestral não está indicado para este paciente, pois é reservado para indivíduos com cirrose hepática ou hepatite B crônica. É correto o que se afirma em:', options: ['III, apenas.', 'I, II e IV, apenas.', 'II e III, apenas.', 'I, II, III e IV.', 'I e IV, apenas.'], correctIndex: 1 },
  { id: 'comvest_2025_023', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Neurologia, Oncologia', text: 'Um paciente de 55 anos com histórico de carcinoma de pulmão em tratamento com quimioterapia e radioterapia apresenta quadro súbito de confusão mental, náuseas, vômitos, cefaleia intensa e disartria. Ao exame físico, há sinais de hiporreflexia e diminuição da força muscular nos membros inferiores. A tomografia computadorizada (TC) de crânio revela múltiplas lesões metastáticas cerebrais. Com base nesse quadro clínico, qual é a abordagem terapêutica inicial mais adequada?', options: ['Iniciar tratamento com antibióticos de amplo espectro, pois o quadro clínico é sugestivo de infecção do sistema nervoso central (SNC) associado à imunossupresão.', 'Iniciar corticoterapia com dexametasona para reduzir o edema cerebral, seguida de avaliação para radioterapia cerebral paliativa, considerando a possibilidade de síndrome de massa ou edema relacionado às metástases.', 'Solicitar avaliação da neurocirurgia para avaliação com urgência da ressecação das lesões metastáticas cerebrais, seguido de quimioterapia sistêmica para controle da doença primária.', 'Iniciar terapia com fármacos antiepilépticos de amplo espectro, visto que as metástases cerebrais podem predispor a convulsões focais.', 'Administrar anticoagulantes de baixo peso molecular para prevenir trombose venosa cerebral, uma vez que o quadro de confusão mental é compatível com síndrome pós-quimioterápica.'], correctIndex: 1 },
  { id: 'comvest_2025_024', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Cardiologia e Alterações Vasculares, Endocrinologia', text: 'Um homem de 62 anos, com diabetes mellitus tipo 2 há 15 anos, hipertensão arterial e dislipidemia, comparece à consulta de rotina. Relata adesão irregular ao tratamento e hábitos de vida sedentários. Nos exames laboratoriais mais recentes, apresenta hemoglobina glicada de 9,2%, colesterol LDL de 160 mg/dL e taxa de filtração glomerular estimada em 65 mL/min/1,73m². O exame físico revela IMC de 31 kg/m² e pressão arterial de 148/92 mmHg. Assinale a alternativa que apresenta a principal causa de morte em pacientes com diabetes mellitus tipo 2:', options: ['Crise de hipoglicemia grave.', 'Doenças cardiovasculares.', 'Câncer pancreático.', 'Acidente vascular encefálico hemorrágico.', 'Nefropatia diabética terminal.'], correctIndex: 1 },
  { id: 'comvest_2025_025', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Políticas Públicas, Planejamento e Gestão em Saúde Pública', text: 'Uma Unidade Básica de Saúde (UBS) apresenta indicadores preocupantes relacionados ao manejo da hipertensão arterial sistêmica, com taxas elevadas de descompensação e baixa adesão ao tratamento. A gestão local decide implementar uma estratégia de Educação Permanente em Saúde (EPS) para qualificar o cuidado a essa condição. Considerando os princípios e a concepção da EPS estabelecidos na Política Nacional de Educação Permanente em Saúde, qual das abordagens a seguir representa corretamente essa estratégia?', options: ['Implementar um protocolo clínico elaborado por consultores externos segundo diretrizes internacionais, sem adaptação à realidade local, acompanhado de um sistema de supervisão hierárquica rígida para garantir a adesão dos profissionais às condutas padronizadas, independentemente do contexto de vida dos usuários e das características da comunidade.', 'Constituir um grupo de trabalho multiprofissional da própria UBS para analisar criticamente o processo de trabalho no cuidado aos hipertensos, identificar problemas locais como barreiras de acesso e falhas na linha de cuidado, construir um plano de intervenção contextualizado às necessidades territoriais e implementar mudanças nas práticas assistenciais de forma integrada com a gestão, serviço, ensino e controle social.', 'Realizar um seminário teórico único sobre hipertensão arterial com palestrantes convidados, focado na apresentação de evidências científicas atualizadas, sem espaço para discussão das práticas cotidianas ou para elaboração de estratégias locais de enfrentamento dos problemas identificados pelos profissionais em sua realidade assistencial.', 'Promover um curso de atualização sobre as Diretrizes Brasileiras de Hipertensão Arterial com metodologias tradicionais de ensino, ministrado por especialistas externos e destinado exclusivamente aos médicos da unidade, com conteúdo padronizado e avaliação final por meio de prova escrita para verificação do conhecimento teórico adquirido.', 'Organizar um programa de capacitação técnica fragmentada por categoria profissional, com cronograma pré-definido pela gestão central sem participação dos trabalhadores na definição dos conteúdos, focado exclusivamente na prescrição medicamentosa e em procedimentos técnicos isolados, desconsiderando determinantes sociais e trabalho em equipe.'], correctIndex: 1 },
  { id: 'comvest_2025_026', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Políticas Públicas, Planejamento e Gestão em Saúde Pública', text: 'O Hospital Regional de Alta Complexidade implementou um programa de residência multiprofissional integrado à Rede de Atenção à Saúde (RAS) de sua região. Durante a reunião do Núcleo Docente Estruturante, discutiu-se a necessidade de reformular o projeto pedagógico para incorporar a Educação Interprofissional (EIP) como estratégia formativa. Nesse contexto, analise as afirmações a seguir sobre a articulação entre a EIP e as RAS no fortalecimento do Sistema Único de Saúde: I.A EIP, ao promover aprendizagem compartilhada entre diferentes profissões, constitui elemento catalisador para a efetivação das RAS, visto que estas se caracterizam como estruturas poliárquicas que demandam competências colaborativas para superar a fragmentação do cuidado. II.O modelo organizacional das RAS, que integra diferentes níveis de atenção à saúde, representa campo privilegiado para o desenvolvimento de práticas interprofissionais, permitindo que residentes compreendam a complexidade dos determinantes do processo saúde-doença em seu território de atuação. III.A implementação da EIP em programas de residência multiprofissional deve priorizar a formação especializada dos profissionais em suas áreas específicas, promovendo posteriormente encontros pontuais entre as diferentes especialidades para discussão de casos complexos. IV.A integração ensino-serviço entre hospital e rede de atenção, mediada pela EIP, potencializa a compreensão da integralidade do cuidado ao proporcionar experiências formativas que transcendem os espaços institucionais isolados e valorizam a continuidade assistencial entre os diferentes níveis de atenção. É correto o que se afirma em:', options: ['II e III, apenas.', 'III, apenas.', 'I, II, III e IV.', 'I, II e IV, apenas.', 'I e IV, apenas.'], correctIndex: 3 },
  { id: 'comvest_2025_027', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'S.S.R., de 24 anos, sexualmente ativa, apresenta-se na clínica queixando-se de dor pélvica moderada há três dias. Ela menciona também disúria ocasional e um leve sangramento vaginal irregular após o término da menstruação, que ocorreu há cerca de uma semana. Ela não tem parceiro definido e relata múltiplos parceiros sexuais nos últimos seis meses. Durante a anamnese, revelou ter tido um DIU inserido há aproximadamente dois meses. Ao exame físico, apresenta febre baixa e dor à palpação no abdome inferior, com sensibilidade à mobilização do colo uterino durante o exame especular. Não são observadas secreções purulentas evidentes. Testes laboratoriais incluem leucocitose no hemograma e aumento da proteína C reativa. A ultrassonografia transvaginal revela espessamento da parede tubária e pequeno acúmulo de líquido na pelve. Com base neste caso clínico, qual é o próximo passo mais apropriado na abordagem diagnóstica e/ou terapêutica?', options: ['Descartar diagnóstico de DIP devido à ausência de secreção purulenta no exame especular e tratar como cistite não complicada.', 'Iniciar imediatamente a administração de antibióticos de amplo espectro para tratar suspeita de doença inflamatória pélvica, sem aguardar resultados de cultura.', 'Aguardar os resultados dos testes de biologia molecular para identificação de clamídia e gonococo antes de decidir sobre o tratamento.', 'Realizar tomografia computadorizada da pelve para obter uma imagem mais detalhada antes de iniciar o tratamento antibiótico.', 'Realizar laparoscopia diagnóstica para confirmação visual da doença inflamatória pélvica antes de iniciar qualquer tratamento.'], correctIndex: 1 },
  { id: 'comvest_2025_028', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Qual das seguintes afirmações sobre os progestagênios isolados orais utilizados na anticoncepção no Brasil é correta?', options: ['A noretisterona e o desogestrel, embora estruturalmente relacionados à 19-nortestosterona, apresentam efeitos androgênicos significativos como acne e hirsutismo devido às suas doses utilizadas.', 'A noretisterona, ao ser utilizada em doses de contracepção, provoca um estímulo androgênico considerável dos efetores terminais na unidade pilossebácea comparado ao desogestrel.', 'O desogestrel é altamente eficaz devido à sua capacidade de reduzir a produção ovariana de testosterona através do bloqueio gonadotrófico, resultando em uma taxa de falha contraceptiva inferior a 1/100 mulheres/ano.', 'Devido ao modo de ação primário da noretisterona, que é o bloqueio do muco cervical, a taxa de falha contraceptiva permanece consistentemente baixa quando não tomada no mesmo horário todos os dias.', 'A drospirenona, além do bloqueio gonadotrófico, possui efeito antiandrogênico e é utilizada em regime contínuo, diretamente contribuindo para uma redução significativa da acne.'], correctIndex: 2 },
  { id: 'comvest_2025_029', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Em relação à anatomia das mamas femininas, analise as seguintes afirmativas e assinale as corretas: I.As mamas são compostas por lóbulos, ductos lactíferos, tecido adiposo e tecido conjuntivo, sendo os lóbulos responsáveis pela produção do leite. II.Os ductos lactíferos convergem para os seios lactíferos, onde o leite é armazenado antes da ejeção pelo mamilo. III.A artéria torácica interna é a principal responsável pela irrigação sanguínea das mamas, enquanto as artérias intercostais desempenham papel secundário. IV.O sistema linfático da mama drena principalmente para os nódulos linfáticos axilares, mas também há drenagem para os nódulos mamários internos. É correto o que se afirma em:', options: ['I, II, III e IV.', 'II e III, apenas.', 'I, II e III, apenas.', 'IV, apenas.', 'I e IV, apenas.'], correctIndex: 4 },
  { id: 'comvest_2025_030', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Uma paciente de 28 anos, previamente saudável, é admitida no hospital com dor pélvica severa e febre há dois dias. Um exame de imagem confirma a presença de um abscesso tubo-ovariano (ATO). Considerando essa condição, qual é a conduta terapêutica mais apropriada, abrangendo tanto o manejo hospitalar quanto o acompanhamento ambulatorial?', options: ['Realizar drenagem imediata do abscesso por via laparoscópica e iniciar tratamento antibiótico apenas após confirmação bacteriológica.', 'Começar com antibióticos endovenosos, e após melhora clínica, continuar com doxiciclina e metronidazol orais por no mínimo três semanas, associando o tratamento do parceiro com dose única de azitromicina.', 'Iniciar tratamento ambulatorial com metronidazol e azitromicina orais, sem necessidade de hospitalização, a menos que a paciente não melhore após 48 horas.', 'Utilizar doxiciclina e azitromicina como primeira linha de antibioticoterapia oral, e manter a paciente em observação hospitalar até que a febre desapareça completamente.', 'Iniciar antibióticos endovenosos com metronidazol ou clindamicina no hospital, mantendo por pelo menos 24 horas, e após estabilidade, administrar azitromicina e doxiciclina oral por 14 dias.'], correctIndex: 1 },
  { id: 'comvest_2025_031', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Sobre as sorologias para toxoplasmose, qual é a conduta recomendada para gestantes com IgG não reagente e IgM reagente, sugerindo uma possível infecção aguda de toxoplasmose?', options: ['Administrar espiramicina na dosagem de 3 g/dia e repetir a sorologia em duas a três semanas.', 'Esperar o aparecimento de IgG antes de qualquer intervenção medicamentosa.', 'Iniciar tratamento com antibióticos de amplo espectro para cobrir outras infecções possíveis.', 'Realizar a pesquisa da infecção fetal imediatamente, sem aguardar novas sorologias.', 'Suspender imediatamente toda a medicação e aguardar o surgimento de sintomas.'], correctIndex: 0 },
  { id: 'comvest_2025_032', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Paciente do sexo feminino, 55 anos de idade, com diagnóstico clínico de menopausa e que realizou histerectomia com ooforectomia bilateral para tratamento do câncer de colo de útero há 6 meses, procura atendimento ginecológico com queixa de fogacho comprometendo qualidade de vida. Paciente com IMC 22 kg/m2, sem outras patologias, com mamografia com resultado "BI-RADS 2" realizada há 6 meses. Isso posto, qual a sua orientação, conforme recomendações da FEBRASGO, para o tratamento desse sintoma?', options: ['Paciente não possui contraindicação à terapia hormonal. Pode ser iniciada terapêutica hormonal com estrogênio para tratamento dos fogachos.', 'Contraindicar terapêutica hormonal e iniciar isoflavonas para o tratamento de fogachos.', 'Considerar iniciar terapêutica hormonal sistêmica para tratamento dos sintomas apenas após 1 ano da histerectomia.', 'Devido histórico de câncer ginecológico, não poderá realizar terapêutica hormonal para o tratamento de fogachos sob nenhuma circunstância.', 'Paciente não possui contraindicação à terapia hormonal, deverá realizar nova mamografia e se mantiver exame classificado como BI-RADS 2 poderá iniciar tratamento com estrogênio e progesterona.'], correctIndex: 4 },
  { id: 'comvest_2025_033', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Durante um atendimento em um ambulatório escola, juntamente com alunos do 8o semestre do curso de medicina que estão tendo seu primeiro contato com a disciplina de ginecologia, uma dupla de alunos avalia uma paciente de 35 anos com queixa de nódulo mamário em mama esquerda há 6 meses. A paciente possui histórico materno de câncer de mama aos 60 anos. Como forma de reforçar o aprendizado dos alunos você os estimula a correlacionar a anatomia da mama com possíveis alterações do exame físico. Sobre o exame físico dessa paciente, assinale a alternativa que melhor se adequa:', options: ['Deverá ser realizado exame físico com foco em região de nódulo que paciente relata.', 'Deverá ser realizada palpação de linfonodos axilares, supra e infraclaviculares e palpação das mamas.', 'Deverá ser realizada inspeção estática e dinâmica das mamas, palpação de cadeias linfonodais axilares, supra e infraclaviculares e palpação de ambas as mamas com expressão mamilar.', 'Deverá ser realizada inspeção estática das mamas e palpação de cadeias de linfonodos axilares, supra e infraclaviculares bem como cadeia linfonadal inguinal e palpação das mamas.', 'Deverá ser realizada inspeção estática e dinâmica das mamas, prosseguindo com palpação de mamas.'], correctIndex: 2 },
  { id: 'comvest_2025_034', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Conforme os critérios de elegibilidade da OMS, o uso da injeção trimestral de acetato de medroxiprogesterona após o parto é considerada em qual categoria e deve ser iniciada em qual período?', options: ['Categoria 1, antes da alta hospitalar.', 'Categoria 2, antes de quatro semanas do parto.', 'Categoria 2, após dois meses do parto.', 'Categoria 1, após seis semanas do parto.', 'Categoria 3, imediatamente após o parto.'], correctIndex: 3 },
  { id: 'comvest_2025_035', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'J.A., uma gestante de 28 anos, está na 30ª semana de gestação. Durante uma consulta de rotina, ela apresenta uma pressão arterial de 160/110 mmHg. Ela não tem histórico de hipertensão na gravidez. Durante o exame, foi observado edema significativo nas mãos e nos tornozelos. Testes laboratoriais indicam trombocitopenia moderada e elevações leves nas enzimas hepáticas. Não há presença significativa de proteinúria. Além disso, um exame de ultrassom revelou restrição do crescimento fetal e alterações dopplervelocimétricas com aumento do índice de pulsatilidade das artérias umbilicais. Com base no quadro clínico apresentado, qual das seguintes interpretações e manejos é a mais apropriada para o caso de J.A.?', options: ['J.A. apresenta sinais clássicos de pré-eclâmpsia devido à manifestação de hipertensão após a 20ª semana de gestação, exigindo administração imediata de anti-hipertensivos e suplementação de cálcio.', 'Os sintomas de J.A. indicam hipertensão gestacional simples, mas devido ao pico pressórico deve ser encaminhada imediatamente ao serviço de emergência.', 'Apesar da ausência de proteinúria significativa, o diagnóstico de pré-eclâmpsia é imperativo devido à hipertensão acompanhada de comprometimento sistêmico e sinais de restrição de crescimento fetal, necessitando de encaminhamento imediato à hospital terciário.', 'O diagnóstico de eclâmpsia é apropriado, exigindo intervenção emergencial com sulfato de magnésio para prevenir convulsões, bem como a preparação para parto imediato.', 'O diagnóstico de pré-eclâmpsia não pode ser feito devido à ausência de proteinúria significativa, mas deve-se realizar anti-hipertensivo endovenoso imediatamente para redução de níveis tensionais.'], correctIndex: 2 },
  { id: 'comvest_2025_036', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Primigesta, 26 anos anos, idade gestacional de 27 semanas apresenta resultado de VDRL de 1:4. Nega história prévia de sífilis. Qual a melhor conduta nesse momento, segundo o Ministério da Saúde, é:', options: ['Está confirmado o quadro de sífilis e está indicado iniciar o tratamento do casal imediatamente.', 'Solicitar FTA-ABS, e caso o resultado seja positivo, iniciar tratamento da sífilis.', 'Realizar o teste treponêmico da gestante e, caso positivo, solicitar VDRL e FTA-ABS do companheiro para avaliar a necessidade de tratamento dele.', 'Realizar o teste treponêmico, mas já se deve iniciar o tratamento do casal imediatamente.', 'Realizar novo VDRL quantitativo para confirmar o diagnóstico e iniciar o tratamento do casal imediatamente.'], correctIndex: 4 },
  { id: 'comvest_2025_037', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'L. S. de 24 anos procura atendimento em ambulatório de ginecologia devido preocupação com exame realizado. Paciente é tabagista e portadora de HIV com tratamento há 2 anos com Lamivudina e Dolutegravir. Relata início da atividade sexual aos 16 anos de idade. Atualmente sem relacionamento fixo, esporadicamente relaciona-se com pessoas do mesmo sexo. Apresenta histórico de lesões cauterizadas de condiloma genital há 2 anos e desde então realiza exames ginecológicos periódicos. Há 1 mês realizou exame de citologia oncótica com resultado: "células escamosas atípicas de significado indeterminado". Isso posto, qual a conduta mais assertiva perante o resultado desse exame, considerando as Diretrizes de Rastreamento do Câncer de Colo de Útero de 2016 do Ministério da Saúde?', options: ['Coletar nova citologia e encaminhar paciente diretamente para cirurgião oncológico devido exame alterado e imunossupressão o que eleva probabilidade de lesões pré-invasivas e invasivas do colo do útero.', 'Devido paciente não ter idade mínima indicada para o início do rastreamento de câncer de colo de útero na população em geral, orientar a paciente a repetir exame dentro de 1 ano quando completará 25 anos de idade.', 'Considerar exame alterado, realizar tratamento de possíveis infecções genitais que tenham comprometido o exame e coletar nova citologia em 14 dias.', 'Considerar exame alterado e seguir fluxograma preconizado para a população em geral de nova coleta de citologia em 6 meses.', 'Considerando estado de imunossupressão que eleva a probabilidade de lesões pré-invasivas, encaminhar paciente diretamente para colposcopia.'], correctIndex: 4 },
  { id: 'comvest_2025_038', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Mulher 23 anos de idade, primigesta com 19 semanas e 3 dias de gravidez, retorna com os resultados dos exames solicitados na primeira consulta de pré-natal, todos sem alterações. Relata que esqueceu de contar que tem o pai, duas tias e uma prima com diabetes mellitus tipo 2. A conduta mais indicada em relação ao rastreamento do diabetes gestacional é:', options: ['Repetir mensalmente a glicemia de jejum.', 'Realizar glicemia de jejum e glicohemoglobina imediatamente.', 'Realizar teste oral de tolerância à glicose (TOTG) com 75g de glicose entre 24 e 28 semanas de gravidez.', 'Realizar glicemia de jejum imediatamente.', 'Realizar teste oral de tolerância à glicose (TOTG) com 75g de glicose imediatamente.'], correctIndex: 2 },
  { id: 'comvest_2025_039', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Considerando os testes diagnósticos para sífilis, identifique a alternativa correta com base nas informações conhecidas sobre sorologia treponêmica e não treponêmica:', options: ['A presença de sinais clínicos como cancro duro ou roséolas não é necessária para confirmar a sífilis adquirida se um teste não treponêmico for reagente.', 'Os testes treponêmicos, como o FTA-Abs, geralmente permanecem positivos durante toda a vida do indivíduo, mesmo após o tratamento efetivo.', 'Testes não treponêmicos raramente apresentam falsos positivos devido à ausência de reações cruzadas.', 'Em casos de sífilis primária, tanto os testes treponêmicos quanto os não treponêmicos são imediatamente positivos após a infecção inicial.', 'Um resultado VDRL com titulação igual ou superior a 1/8 é sempre indicativo de infecção ativa por sífilis, independente do contexto clínico.'], correctIndex: 1 },
  { id: 'comvest_2025_040', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'M.S., 58 anos, refere menopausa há 6 anos, com sintomas significativos de fogachos, suores noturnos e insônia. Paciente apresenta hipertensão arterial controlada com medicação, diabetes tipo 2 controlado por dieta e metformina e hepatite C crônica. Possui histórico pessoal de tratamento de carcinoma de células escamosas de colo de útero, tratado com sucesso há 10 anos. Apresenta nessa consulta, exames laboratoriais normais e mamografia normal. M.S. vem à consulta buscando alívio para seus sintomas menopáusicos. Ela está interessada em iniciar a terapia de reposição hormonal (TRH) e pergunta sobre os riscos associados, dada sua história médica. Com base no histórico médico de Maria e nas diretrizes atuais sobre TRH, é correto afirmar que:', options: ['A hepatite C é uma contraindicação absoluta para TRH devido à possibilidade de agravamento da função hepática.', 'História de câncer ginecológico contraindica a TRH devido ao risco de metástase.', 'A TRH não está contraindicada em casos de hipertensão arterial controlada e antecedentes pessoais de carcinoma de células escamosas do colo do útero.', 'A presença de diabetes controlado impede o uso de TRH, devido ao aumento do risco cardiovascular.', 'Mulheres na pós-menopausa não devem iniciar TRH devido ao risco aumentado de eventos tromboembólicos.'], correctIndex: 2 },
  { id: 'comvest_2025_041', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Gestante com 24 anos de idade e idade gestacional de 22 semanas apresenta resultado de hemograma de 10,1 g/dL. No que se refere a suplementação de ferro, deve-se prescrever:', options: ['120 a 240 mg de ferro elementar, em tomada única ao dia.', '120 a 240 mg de sulfato ferroso, dividido em duas tomadas ao dia.', '109 a 200 mg de sulfato ferroso, em tomada única ao dia.', '30 a 80 mg de sulfato ferroso, em tomada única ao dia.', '40 a 100 mg de ferro elementar, dividido em duas tomadas ao dia.'], correctIndex: 0 },
  { id: 'comvest_2025_042', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Paciente de 27 anos, G2P1A0, comparece à consulta de pré-natal com 10 semanas de gestação pela data da última menstruação, trazendo o exame de ultrassonografia transvaginal mostrado na imagem. Relata episódios de sangramento vaginal leve e intermitente nas últimas duas semanas. Ao exame físico, apresenta altura uterina maior que o esperado para a idade gestacional e beta-hCG quantitativo com valores acima do percentil 95 para a idade gestacional. Qual diagnóstico você enfatizaria como mais provável e que merece atenção imediata?', options: ['Neoplasia trofoblástica gestacional em fase inicial, evidenciada pelo aspecto heterogêneo do conteúdo intrauterino sem embrião visível.', 'Gestação molar parcial, caracterizada pela presença de material embrionário associado a alterações placentárias císticas.', 'Abortamento retido com descolamento placentário parcial, evidenciado pela presença de saco gestacional irregular e áreas de hemorragia periplacentária.', 'Gestação gemelar dicoriônica com um feto viável e outro com desenvolvimento anormal, sugerida pela visualização de estruturas distintas na cavidade uterina.', 'Gestação ectópica cornual complicada, indicada pelo posicionamento excêntrico do saco gestacional e áreas heterogêneas adjacentes.'], correctIndex: 1 },
  { id: 'comvest_2025_043', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Sobre o herpes simples vírus (HSV) e suas manifestações genitais, analise as seguintes afirmativas e assinale as corretas: I.O herpes genital se manifesta por pequenas vesículas que podem atingir a região anal e perianal, especialmente se não houver um bom controle imunológico. II.Causas de imunossupressão incluem fatores como desnutrição, uso de quimioterapia, e condições como AIDS, os quais podem levar a lesões herpéticas significativas e prolongadas. III.O diagnóstico de herpes genital é feito exclusivamente através de testes laboratoriais, dada a dificuldade de identificação clínica. IV.O tratamento é fundamental para a regressão das lesões de herpes genital, mesmo em indivíduos imunocompetentes. V.A presença de lesão herpética em mucosas por mais de 30 dias é considerada um caso suspeito de AIDS de acordo com o Centro de Controle de Doenças Americano. É correto o que se afirma em:', options: ['II e V, apenas.', 'I, III e IV, apenas.', 'I, II e V, apenas.', 'III e IV, apenas.', 'I, II, III, IV e V.'], correctIndex: 2 },
  { id: 'comvest_2025_044', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Considere as seguintes afirmações sobre o acretismo placentário: I.A placenta increta é caracterizada por uma invasão que perfura o peritônio e pode atingir órgãos vizinhos. II.A placenta acreta é mais comum, representando 80% dos casos de acretismo, e está associada à adesão da placenta ao miométrio. III.O risco de placenta acreta aumenta com o número de cesáreas anteriores, principalmente quando há presença de placenta prévia. IV.Os achados sonográficos sugestivos de placenta acreta incluem hipervascularização e disrupção da interface serosa-parede vesical. Com base no texto, é correto o que se afirma em:', options: ['II e III, apenas.', 'I, II, III e IV.', 'I e IV, apenas.', 'II, III e IV, apenas.', 'I, apenas.'], correctIndex: 3 },
  { id: 'comvest_2025_045', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Considere as seguintes afirmações sobre o diagnóstico de diabetes na gestação, conforme o estudo HAPO-2008 e as diretrizes do IADPSG: I.Uma glicemia de jejum inferior a 92 mg/dL na primeira consulta pré-natal é considerada normal. II.O teste de tolerância à glicose oral de 75 g (TOTG-75) entre 24 e 28 semanas de gravidez é conduzido com dieta controlada durante três dias antes. III.A glicemia de jejum entre 92 e 125 mg/dL indica diabetes mellitus gestacional (DMG). IV.Um valor de glicemia ao acaso de 200 mg/dL, confirmado por glicemia de jejum ou HbA1c, sugere diabetes pré-gestacional. Com base no texto, é correto o que se afirma em:', options: ['II, apenas.', 'I, II, III e IV.', 'I e II, apenas.', 'I, III e IV, apenas.', 'III e IV, apenas.'], correctIndex: 3 },
  { id: 'comvest_2025_046', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Diante do manejo de um caso de sangramento uterino anormal crônico (SUA), considere uma paciente de 48 anos com fatores de risco para carcinoma endometrial e histórico familiar de coagulopatia, qual deve ser a abordagem diagnóstica mais indicada?', options: ['Executar histerossonografia com infusão salina para visualização de patologias intracavitárias e proceder com biópsia de endométrio para excluir malignidade.', 'Realizar biópsia de endométrio, seguido de histerossonografia com infusão salina somente se a biópsia for inconclusiva.', 'Começar com avaliação histopatológica por biópsia de endométrio e prosseguir com testes hematológicos para coagulopatias, como fator de von Willebrand, somente após resultados de ultrassonografia.', 'Realizar ultrassonografia pélvica seguida imediatamente de histeroscopia diagnóstica para investigação de anormalidades estruturais.', 'Avaliar exclusivamente por ultrassonografia pélvica devido à alta sensibilidade, retardando outras avaliações invasivas.'], correctIndex: 0 },
  { id: 'comvest_2025_047', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Dentre as alternativas a seguir, selecione aquela em que a contracepção com progestagênio seria considerada a melhor opção.', options: ['Durante a lactação, apenas nas primeiras 6 semanas após o parto.', 'Em pacientes com lúpus eritematoso sistêmico na presença de anticorpos antifosfolípides.', 'Em mulheres com trombofilias conhecidas ou histórico de tromboembolismo venoso (TVP ou TEP).', 'Em mulheres com hipertensão arterial grave, acima de 160/100 mmHg.', 'Em mulheres fumantes com menos de 35 anos sem outros fatores de risco.'], correctIndex: 2 },
  { id: 'comvest_2025_048', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Durante uma consulta pré-natal, uma paciente é avaliada e identificada como de alto risco para pré-eclâmpsia. Qual das seguintes intervenções baseadas em evidências deve ser implementada para reduzir esse risco?', options: ['Uso de ômega-3 para melhorar resultados gestacionais.', 'Administrar vitamina D como parte do regime preventivo.', 'Suplementação de cálcio de 1 a 2 g ao dia e AAS de 100-150 mg/dia.', 'Iniciar restrição de sal na dieta para todas as pacientes de risco.', 'Recomendar o uso de antioxidantes como medida regular.'], correctIndex: 2 },
  { id: 'comvest_2025_049', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'A.G.S., uma mulher de 24 anos, no primeiro trimestre de sua primeira gravidez, procura atendimento médico relatando sangramento vaginal leve que ocorreu esporadicamente nos últimos dois dias, associado a dor abdominal tipo cólica de intensidade leve. Ela menciona não ter tido nenhum episódio de dor intensa ou sangramento mais abundante. Durante o exame físico, o orifício interno do colo do útero está fechado, sem evidência de sangramento vaginal ativo no momento da consulta. Não há febre, corrimento anormal ou outros sinais de infecção. Considerando esses achados clínicos e os fatores de risco usuais, qual é o diagnóstico mais provável para a situação de A.G.S., e qual seria a melhor conduta a seguir?', options: ['Aborto espontâneo completo, caracterizado pela expulsão de todos os produtos da concepção. A melhor conduta é observação e controle de hCG para assegurar a conclusão do aborto.', 'Ameaça de aborto, devido à presença de dor tipo cólica leve, sangramento leve, e colo uterino fechado. A melhor conduta seria acompanhamento expectante com orientações sobre sinais de alerta.', 'Ameaça de aborto, devido à presença de dor tipo cólica leve, sangramento leve, e colo uterino fechado. A melhor conduta seria realização imediata em serviço de emergência de ultrassonografia transvaginal para confirmar vitalidade do embrião e internação para controle de sangramento.', 'Gravidez ectópica, devido à associação de dor abdominal e sangramento anormal. A conduta seria realização de ultrassonografia transvaginal imediata para localização gestacional.', 'Aborto inevitável, indicando abertura cervical com expiração iminente do conteúdo uterino. A melhor conduta é a internação hospitalar para manejo imediato.'], correctIndex: 1 },
  { id: 'comvest_2025_050', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Mulher, G3P3A0, 45 anos, apresenta citologia oncótica com lesão intraepitelial de alto grau. A conduta recomendada de acordo com as diretrizes do Ministério da Saúde do Brasil é:', options: ['Encaminhá-la para colposcopia imediatamente.', 'Repetir a citologia oncótica em 6 meses.', 'Solicitar teste rápido para HIV, hemograma e dosagens hormonais.', 'Indicar histerectomia total, considerando que a paciente já tem a prole definida.', 'Repetir a citologia oncótica imediatamente.'], correctIndex: 0 },
  { id: 'comvest_2025_051', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Durante a gravidez, as infecções do trato urinário (ITUs) aumentam devido a alterações fisiológicas específicas. Considere uma paciente gestante que desenvolve uma ITU. Além da presença de bactérias na urina, qual/quais fatore(s) fisiológico(s) intrínseco(s) à gravidez contribuem significativamente para o desenvolvimento e a persistência dessa condição, e qual é o mecanismo fisiológico subjacente que mais predisporia uma grávida a complicações urinárias desiguais entre os dois rins?', options: ['A ação mecânica compressiva sobre o trato urinário que afeta mais frequentemente ureter e, consequentemente, rim direitos.', 'A ação relaxante de prostaciclina e progesterona, que diminui o tônus muscular, levando à dilatação e hipomotilidade do trato urinário.', 'A presença de aminoacidúria, que age como um fator significativo na mudança do pH urinário, contribuindo para o crescimento bacteriano.', 'A compressão mecânica pelo posicionamento e discreta rotação uterina, que afeta mais frequentemente o ureter e o rim esquerdos.', 'O fato de que a dilatação vesicoureteral fisiológica é mais pronunciada do lado esquerdo devido à posição do útero em crescimento.'], correctIndex: 1 },
  { id: 'comvest_2025_052', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Paciente grávida de 8 semanas se apresenta para um exame de ultrassonografia devido à ausência de sintomas de gravidez, como náuseas ou seios sensíveis, nas últimas 2 semanas. Durante o exame ultrassonográfico, são observados os seguintes achados: Saco gestacional com um diâmetro médio de 26 mm. Embrião com comprimento crânio-nádegas de 8 mm, sem atividade cardíaca detectada. Histórico de ultrassom anterior há três semanas que demonstrava um saco gestacional vazio. Com base nesses achados ultrassonográficos, qual é o diagnóstico mais provável para esta paciente?', options: ['Avaliação inadequada da idade gestacional, sugerindo repetição imediata do ultrassom para confirmação.', 'Avaliação inadequada da idade gestacional, sugerindo reavaliação em 48 horas.', 'Gravidez normal em estágio inicial, sugerindo reavaliação em duas semanas.', 'Óbito embrionário, confirmado pela ausência de desenvolvimento normal e atividade cardíaca.', 'Gravidez normal em estágio inicial, sugerindo reavaliação em 1 semana.'], correctIndex: 3 },
  { id: 'comvest_2025_053', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Sobre a amenorreia primária e secundária, leia as assertivas a seguir: I.Amenorreia primária é definida como ausência de menstruação e caracteres sexuais secundários em meninas aos 12 anos de idade. II.A síndrome de Kallmann cursa com hiposmia e disgeusia. III.Na síndrome de Turner, o cariótipo esperado é 45X. IV.A síndrome de Sheehan pode ocorrer em mulheres após parto que tiveram complicações como atonia uterina. V.Na síndrome de Mayer-Rokitansky-Kuster-Hauser do subtipo 2 pode haver alterações em órgãos extra-genitais como rins e coluna. É correto o que se afirma em:', options: ['I, II, III, IV e V.', 'I e II, apenas.', 'I, III e V, apenas.', 'II e IV, apenas.', 'III, IV e V, apenas.'], correctIndex: 2 },
  { id: 'comvest_2025_054', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Dada a complexidade do risco de tromboembolismo venoso (TEV) associado ao uso de contraceptivos orais combinados (COCs), especialmente considerando a escolha de formulações hormonais, qual seria a estratégia mais eficaz para minimizar esse risco em pacientes sem história de TEV, mas com predisposição genética para trombofilias?', options: ['Prescrever uma formulação de COC com levonorgestrel em combinação com estrogênios com potencial trombogênico reduzido, como o estetrol.', 'Iniciar a paciente em COC com progestagênios com ação antiandrogênica, como drospirenona, independentemente do componente estrogênico.', 'Recomendar a pesquisa de trombofilias hereditárias em todas as pacientes antes do início do uso de COCs.', 'Optar por uma formulação de COC com progestagênios com menor ação androgênica e uma dose média de 50 mcg de etinilestradiol.', 'Escolher um COC com levonorgestrel associado a doses elevadas de etinilestradiol para garantir eficácia contraceptiva sem considerar o risco de TEV.'], correctIndex: 0 },
  { id: 'comvest_2025_055', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Um homem indígena de 52 anos comparece à Unidade Básica de Saúde acompanhado de sua esposa, que atua como tradutora, pois ele fala pouco português. Durante a consulta, são realizadas duas aferições da pressão arterial em momentos distintos, ambas apresentando valores de 148/94 mmhg. O paciente não refere sintomas, mas menciona que seu pai faleceu jovem por "problemas no coração". Considerando os princípios da Política Nacional de Atenção à Saúde dos Povos Indígenas e o manejo adequado da hipertensão arterial nessa população, assinale a alternativa correta:', options: ['A terapia medicamentosa deve ser iniciada imediatamente com esquema de múltiplos fármacos, sem considerar medidas não farmacológicas, devido à maior vulnerabilidade genética dos indígenas às complicações cardiovasculares.', 'O médico deve explicar o diagnóstico de hipertensão utilizando termos técnicos precisos, garantindo assim a compreensão científica da condição, independentemente das barreiras linguísticas ou culturais.', 'A abordagem deve reconhecer que a hipertensão arterial é frequentemente assintomática, integrar os saberes tradicionais sobre saúde-doença da etnia do paciente no plano terapêutico, e envolver profissionais habilitados quando disponíveis para facilitar a comunicação e a adesão ao tratamento.', 'O diagnóstico de hipertensão em indígenas requer valores pressóricos mais elevados que os utilizados para a população geral, devido às diferenças genéticas que tornam essa população naturalmente mais resistente aos efeitos da pressão elevada.', 'As orientações sobre mudanças no estilo de vida devem focar na substituição da alimentação tradicional indígena por uma dieta ocidental padronizada, cientificamente comprovada para o controle da hipertensão em qualquer população.'], correctIndex: 2 },
  { id: 'comvest_2025_056', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Direito Sanitário', text: 'A participação da comunidade na gestão do SUS e o planejamento regionalizado dos serviços de saúde são aspectos centrais das normas que regulam o sistema. Considerando esse contexto, assinale a alternativa correta.', options: ['A Lei nº 8.142/1990 restringe a participação social no SUS às conferências nacionais, sem obrigatoriedade de instâncias estaduais e municipais.', 'A Lei nº 8.142/1990 estabelece a participação da comunidade na gestão do SUS por meio de conselhos e conferências de saúde.', 'O Decreto nº 7.508/2011 determina que o financiamento da saúde no Brasil deve ser exclusivamente de responsabilidade da União, sem contrapartida de estados e municípios.', 'A regionalização da saúde, prevista no Decreto nº 7.508/2011, centraliza a gestão dos serviços apenas no nível estadual, sem envolvimento dos municípios.', 'Os Conselhos de Saúde, criados pela Lei nº 8.142/1990, possuem caráter consultivo, sem poder deliberativo na formulação e fiscalização de políticas de saúde.'], correctIndex: 1 },
  { id: 'comvest_2025_057', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Em relação à anatomia detalhada da pelve feminina, analise as seguintes afirmativas e assinale as corretas: I.O ligamento útero-sacro se estende do colo do útero até o sacro e possui fibras nervosas que transportam sensações dolorosas. II.A artéria uterina, principal fonte de irrigação do útero, origina-se das artérias ilíacas internas. III.O espaço retopúbico, também conhecido como saco de Douglas, é uma bolsa peritoneal localizada entre a bexiga e a parede anterior do útero. IV.As artérias ovarianas originam-se diretamente da aorta abdominal e têm anastomoses com as artérias iliolombares. É correto o que se afirma em:', options: ['I, II e IV, apenas.', 'III e IV, apenas.', 'III, apenas.', 'I, II, III e IV.', 'I e II, apenas.'], correctIndex: 0 },
  { id: 'comvest_2025_058', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Mulher de 27 anos, G3P3A0, apresenta citologia oncótica com lesão intraepitelial de baixo grau. A conduta recomendada conforme as diretrizes atuais é?', options: ['Encaminhá-la para colposcopia imediatamente.', 'Repetir a citologia oncótica em 12 meses.', 'Solicitar teste sorológico para HPV de alto risco.', 'Indicar conização diagnostica.', 'Realizar vacinação contra HPV.'], correctIndex: 2 },
  { id: 'comvest_2025_059', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Mulher de 35 anos com histórico familiar de câncer de mama (mãe diagnosticada aos 45 anos) procura atendimento solicitando avaliação do risco de câncer de mama. Qual das seguintes condutas é mais adequada?', options: ['Realizar mamografia de rotina anualmente a partir dos 35 anos.', 'Solicitar RM de mamas como rastreamento primário.', 'Avaliar história familiar detalhada e considerar aconselhamento genético e testes genéticos se indicado.', 'Iniciar análogo de hormônio liberador de hormônio luteinizante para reduzir risco hormonal.', 'Realizar ultrassom de mamas mensalmente.'], correctIndex: 2 },
  { id: 'comvest_2025_060', banca: 'COMVEST-UNICAMP', cycle: 'Ciclo Clínico', subject: 'Ginecologia e Obstetrícia', text: 'Uma mulher de 40 anos, nulípara, com útero aumentado e irregular, apresenta menorragia progressiva há 2 anos. Ao exame ultrassonográfico transvaginal, evidencia-se mioma intramural de 4 cm e endometriose associada. Considerando o desejo de preservação uterina e a complexidade do caso, qual é a melhor abordagem terapêutica?', options: ['Histerectomia total abdominal como tratamento definitivo.', 'Apenas tratamento clínico com análogos de GnRH indefinidamente.', 'Miomectomia por via laparoscópica ou histeroscópica associada a tratamento da endometriose.', 'Ablação endometrial como solução única para controlar o sangramento.', 'Embolização arterial uterina isolada sem tratamento de endometriose.'], correctIndex: 2 },
];
